sql:
SELECT property_id, roof_style
FROM exteriors
WHERE roof_age > 20 AND exterior_features LIKE '%Solar%';

SELECT sale_type, AVG(sale_price) AS average_sale_price
FROM sales
GROUP BY sale_type;

SELECT sales.property_id, sales.sale_price, exteriors.roof_matl, exteriors.exterior2nd
FROM sales
JOIN exteriors ON sales.property_id = exteriors.property_id;

SELECT property_id, full_bath 
FROM rooms 
WHERE full_bath = (
    SELECT MAX(full_bath) 
    FROM rooms 
    WHERE full_bath < (
        SELECT MAX(full_bath) 
        FROM rooms
    )
);

SELECT AVG(sale_price) AS avg_sale_price
FROM sales
WHERE sale_type = 'WD';

external_knowledge:
- 'Well-maintained' refers to properties with good conditions (e.g., garage condition 'TA', basement quality 'TA'); 
- 'Warranty deeds' is another term for 'WD' sale type; 
- 'Large garages' refers to garages with more than one car capacity.

sql:
SELECT heating_age
FROM heating
WHERE property_id = 1;

SELECT AVG(sale_price) AS average_sale_price
FROM sales
WHERE mo_sold = 7 AND sale_type = 'WD';

SELECT COUNT(*), AVG(pool_size) AS avg_pool_size
FROM pools
WHERE pool_size > 0;

SELECT roof_matl, mas_vnr_area, exter_cond, exterior_color
FROM exteriors
ORDER BY mas_vnr_area ASC;

SELECT property_id, bsmt_qual, bsmt_exposure, bsmt_fin_sf1, bsmt_fin_sf2 
FROM basements 
ORDER BY property_id ASC;

SELECT property_id, gr_liv_area, bsmt_full_bath
FROM living_spaces
WHERE bsmt_full_bath > 0;

SELECT AVG(ls.gr_liv_area) AS average_living_space_area
FROM living_spaces ls
JOIN pools p ON ls.property_id = p.property_id;

SELECT *
FROM exteriors
ORDER BY roof_age DESC;
